import React, { useState } from 'react';

type Item = {
  object_id: string;
  fields: Record<string, any>; // generic fields for all types
};

type ItemsTableProps = {
  containerId: string;
  items: Item[];
  error?: string;
};

export const ItemsTable: React.FC<ItemsTableProps> = ({ containerId, items, error }) => {
  const [expandedCells, setExpandedCells] = useState<Set<string>>(new Set());

  const toggleCell = (cellId: string) => {
    setExpandedCells(prev => {
      const copy = new Set(prev);
      if (copy.has(cellId)) copy.delete(cellId);
      else copy.add(cellId);
      return copy;
    });
  };

  return (
    <div style={{ padding: 20 }}>
      <h1>Items in Container: {containerId}</h1>

      {error && <div style={{ color: 'red', marginBottom: 10 }}>Error: {error}</div>}

      {items.length > 0 ? (
        <table style={{ width: '100%', borderCollapse: 'collapse', tableLayout: 'fixed' }}>
          <thead>
            <tr>
              <th>Object ID</th>
              <th>Name</th>
              <th>Description</th>
              <th>Content</th>
              <th>External ID</th>
              <th>Creator</th>
              <th>Data Type ID</th>
              <th>Tag Index</th>
              <th>Previous</th>
            </tr>
          </thead>
          <tbody>
            {items.map(item => (
              <tr key={item.object_id}>
                {[
                  item.object_id,
                  item.fields.name,
                  item.fields.description,
                  item.fields.content,
                  item.fields.external_id,
                  item.fields.creator,
                  item.fields.data_type_id,
                  item.fields.tag_index,
                  item.fields.prev ?? '-',
                ].map((value, idx) => {
                  const cellId = `${item.object_id}-${idx}`;
                  const isExpanded = expandedCells.has(cellId);
                  return (
                    <td key={idx} style={{ border: '1px solid #ddd', padding: '10px' }}>
                      <div
                        style={{
                          maxHeight: isExpanded ? 'none' : '50px',
                          overflow: 'hidden',
                          cursor: 'pointer',
                          position: 'relative',
                          paddingRight: '20px',
                        }}
                        onClick={() => toggleCell(cellId)}
                      >
                        {value}
                        <span
                          style={{
                            position: 'absolute',
                            right: 5,
                            bottom: 5,
                            fontSize: 12,
                            color: '#555',
                          }}
                        >
                          {isExpanded ? '▲' : '▼'}
                        </span>
                      </div>
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      ) : (
        <p>No items found in this container.</p>
      )}
    </div>
  );
};
